package be.schaubroeck.lpb.rkm.rekenmotor.main;

import be.schaubroeck.lpb.rkm.rekenmotor.service.web.RekenProces;
import be.schaubroeck.lpb.rkm.rekenmotor.service.web.RekenProcesCentral;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.service.AdminService;
import be.schaubroeck.lpb.tools.service.LockLogService;
import lombok.Setter;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.support.ClassPathXmlApplicationContext;

import java.util.Calendar;
import java.util.List;

@Slf4j
public class StandAloneHerberekenen {

    public static void start(Integer adminid, String serverBundle) throws Exception {
        ClassPathXmlApplicationContext context = new ClassPathXmlApplicationContext(serverBundle);
        StandAloneHerberekenen standalone = (StandAloneHerberekenen) context.getBean("standAloneHerberekenen");

        MainHelper.shutdownSchedulers(context);

        standalone.startTimeLogging();
        standalone.doeBerekeningen(adminid);
        standalone.endTimeLogging();
        context.close();

    }

    private long timeMillis;

    public void startTimeLogging() {
        timeMillis -= Calendar.getInstance().getTimeInMillis();
    }

    public void endTimeLogging() {
        timeMillis += Calendar.getInstance().getTimeInMillis();
        log.info("Duur: {} seconden", timeMillis / 1000.0);
    }

    @Autowired
    private AdminService adminService;
    @Autowired
    protected RekenProcesCentral rekenProcesCentral;
    @Autowired
    private LockLogService lockLogService;

    @Setter
    private boolean throwExceptions = false;

    public void doeBerekeningen(Integer adminid) throws Exception {
        try {
            Admin admin = adminService.getById(adminid);
            if (admin == null) {
                throw new RuntimeException("Admin werd niet gevonden, adminid = " + adminid);
            }

            log.info("Herreken admin : {}", admin.getId());
            Long procesId = doeBerekeningen(admin);

            Thread.sleep(1000);

            boolean procesRuns = true;
            while (procesRuns) {
                RekenProces proces = rekenProcesCentral.getProces(procesId);
                log.info("proces : %{} ({}/{})", proces.getPercentageProgress(), proces.getVerwerkt(), proces.getTotaal());
                procesRuns = !proces.isDone();
                Thread.sleep(1000);
            }

            log.info("Berekenen done");

        } catch (Exception e) {
            handleException(e);
        }
    }

    private Long doeBerekeningen(Admin admin) {
        checkLopendeRekenProcessen(admin);

        String actor = "rekenmotor-berekenen.sh";
        String omschijving = "Herrekenen gerekende opdrachten.";

        if (lockLogService.rekenenBezig(admin, actor)) {
            throw new MessageException("Rekenen geblokkeerd door locks.");
        }

        return rekenProcesCentral.startHerrekenProces(admin, omschijving, actor);
    }

    private void checkLopendeRekenProcessen(Admin admin) {
        // maximaal één proces tegelijk (per administratie)
        List<RekenProces> processen = rekenProcesCentral.getProcessen(admin);
        for (RekenProces proces : processen) {
            if (!(proces.isFinished() || proces.getStopFlag())) {
                throw new MessageException("Maximaal één proces tegelijk, er is al een proces bezig met rekenen.");
            }
        }
    }

    private static final String FATAL_MESSAGE = "Er werd een Exception gegooid bij rekenen";

    private void handleException(Exception exception) throws Exception {
        if (throwExceptions) {
            throw new MessageException(FATAL_MESSAGE, exception);
        } else {
            log.error(FATAL_MESSAGE, exception);
            throw exception;
        }
    }

}
